def _model_dump(model: Any, by_alias: bool = False) -> Any:
    """Dump a model to a plain Python structure.

    Will attempt common methods from pydantic BaseModel; otherwise returns the model.
    """
    if hasattr(model, "model_dump"):
        try:
            return model.model_dump(by_alias=by_alias)
        except TypeError:
            return model.model_dump()
    if hasattr(model, "dict"):
        return model.dict(by_alias=by_alias)
    return model


def _get_model_config(model: Any) -> Any:
    """Return model configuration (Config class or equivalent)."""
    return getattr(model, "Config", None)


