def is_scalar_field(field: Any) -> bool:
    """Return True if the provided field should be considered scalar."""
    return field_annotation_is_scalar(get_annotation_from_field_info(field))


def is_sequence_field(field: Any) -> bool:
    """Return True if the provided field should be considered a sequence."""
    return field_annotation_is_sequence(get_annotation_from_field_info(field))


def is_scalar_sequence_field(field: Any) -> bool:
    """Return True if the provided field is a sequence of scalar values."""
    return field_annotation_is_scalar_sequence(get_annotation_from_field_info(field))


def is_bytes_field(field: Any) -> bool:
    """Return True if the field is typed as bytes (or Optional[bytes])."""
    return is_bytes_or_nonable_bytes_annotation(get_annotation_from_field_info(field))


def is_bytes_sequence_field(field: Any) -> bool:
    """Return True if the field is typed as a sequence of bytes."""
    return is_bytes_sequence_annotation(get_annotation_from_field_info(field))


def copy_field_info(field: Any) -> Any:
    """Return a shallow copy of field metadata where possible."""
    try:
        return copy(field)
    except Exception:
        return field


def serialize_sequence_value(value: Any) -> Any:
    """Serialize a sequence value into a JSON-friendly form.

    For now, convert sequences to lists and leave inner values unchanged.
    """
    if value is None:
        return None
    if value_is_sequence(value):
        return [v for v in value]
    return value


def get_missing_field_error(name: str, *, location: Tuple = ()) -> Dict[str, Any]:
    """Return a standardized error dict indicating a missing field."""
    return {"loc": tuple(location) + (name,), "msg": "field required", "type": "value_error.missing"}


def create_body_model(name: str, field_definitions: Dict[str, Any], base_class: Type[BaseModel] = BaseModel) -> Type[BaseModel]:
    """Create a pydantic body model dynamically from field definitions.

    field_definitions should be a dict mapping field names to (type, default) tuples
    similar to pydantic.create_model.
    """
    try:
        return create_model(name, __base__=base_class, **field_definitions)
    except Exception:
        # Fallback to a minimal Model subclass
        return create_model(name, **field_definitions)


